<template>
  <v-container fluid class="pa-6 pt-4 fill-height cctv-manage">
    <v-row no-gutters class="fill-height">
      <v-sheet width="100%" height="33" class="d-flex align-center">
        <h3 class="font-weight-bold">{{ $t('safetyManager') }}</h3>
      </v-sheet>
      <v-sheet width="100%" height="calc(100% - 33px)" class="pt-0">
        <i-card-top
            :useBtnList="buttonUseList"
            @btnAdd="btnAdd()"
            @btnSearch="btnSearch()"
            @btnSave="btnSave()"
            @btnDelete="btnDelete()"
            class="d-flex mb-0"
        >
          <template #body>
            <v-sheet height="100%" class="d-flex align-center">
              <v-spacer />
            </v-sheet>
          </template>
        </i-card-top>
        <v-layout column>
          <DxDataGrid
              :key="gridKey"
              id="checkInfoDataGrid"
              class="cctv-api-server-manage-layout-col-height"
              :ref="dxDataGridRef"
              :data-source="cctvDataSource"
              :remote-operations="false"
              :show-borders="true"
              :show-row-lines="true"
              :column-auto-width="true"
              :allow-column-resizing="true"
              :allow-column-reordering="true"
              :repaint-changes-only="false"
              :focused-row-enabled="true"
              key-expr="gridKey"
              @editing-start="onEditingStart"
              @editor-preparing="onEditorPreparing"
              @focused-row-changed="onFocusedRowChanged"
          >
            <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />
            <DxScrolling row-rendering-mode="standard" />
            <DxSelection select-all-mode="allPages" show-check-boxes-mode="always" mode="multiple" />
            <DxColumn data-field="monitoring_grp_id" data-type="string" css-class="devest-grid-header-require" :caption="$t('grpID')" alignment="center" :visible="true" :allow-editing="true" >
              <DxLookup :data-source="cctvGrouprDataSource" display-expr="grp_nm" value-expr="monitoring_grp_id" />
            </DxColumn> 
            <DxColumn data-field="token" data-type="string" css-class="devest-grid-header-require" :caption="$t('token')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="chat_id" data-type="string" css-class="devest-grid-header-require" :caption="$t('chatID')" alignment="center" :visible="true" :allow-editing="true" />
            <DxColumn data-field="created_at" data-type="string" :caption="$t('createdDate')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="created_by" data-type="string" :caption="$t('writer')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="updated_at" data-type="string" :caption="$t('updatedDate')" alignment="center" :visible="true" :allow-editing="false" />
            <DxColumn data-field="updated_by" data-type="string" :caption="$t('modifier')" alignment="center" :visible="true" :allow-editing="false" />       <DxColumn
                data-field="notification_on"
                data-type="string"
                :caption="$t('alertOnOff')"
                alignment="center"
                :visible="true"
                :allow-editing="false"
                cell-template="alertOnOff"
            />
            <template #alertOnOff="{ data: cellInfo }">
              <template>
                <template v-if="cellInfo.data.notification_on">
                  <!-- {{ $t('running') }} -->
                  <v-icon color="success">mdi-cctv</v-icon>
                </template>
                <template v-else>
                  <v-icon color="red">mdi-cctv</v-icon>
                </template>
              </template>
            </template>
            <DxColumn
                data-type="string"
                caption=""
                alignment="center"
                :visible="true"
                :allow-editing="false"
                header-cell-template="cctvProcessHeader"
                cell-template="cctvProcess"
            />
            <template #cctvProcessHeader="{ data: cellInfo }">
              <v-sheet color="white" class="d-flex align-center justify-start">
                <v-btn outlined text elevation="0" width="80" height="25" class="pa-1 pr-2 rounded-0" @click="onFullRun()">
                  <span class="primary--text text-caption">{{ $t('fullRun') }}</span>
                </v-btn>
              </v-sheet>
            </template>
            <template #cctvProcess="{ data: cellInfo }">
              <template>
                <v-sheet color="transparent" class="d-flex align-center justify-center">
                  <v-btn outlined text elevation="0" width="60" height="25" class="pa-1 pr-2 mr-2 rounded-0" @click="onRun(cellInfo.data.monitoring_grp_id + '_' + cellInfo.data.chat_id, true)">
                    <span class="primary--text text-caption">{{ $t('run') }}</span>
                  </v-btn>
                  <v-btn outlined text elevation="0" width="60" height="25" class="pa-1 pr-2 mr-1 rounded-0" @click="onRun(cellInfo.data.monitoring_grp_id + '_' + cellInfo.data.chat_id, false)">
                    <span class="error--text text-caption">{{ $t('end') }}</span>
                  </v-btn>
                </v-sheet>
              </template>
            </template>
          </DxDataGrid>
        </v-layout>
      </v-sheet>
    </v-row>
  </v-container>
</template>

<script>
import baseview from '@/views/base/baseview.vue'
import BaseDataGrid from '@/views/base/BaseDataGrid.vue'

import { getUserCd } from '@/utils/token'
import {
  getManagerList,
  saveManager,
  saveManager_,
  deleteCCTV,
  runCCTVProcessAll,
  runCCTVProcess,
  endCCTVProcess,
  checkCCTVProcessAll,
  getGroupList,
  getManager,
  runAlarm,
  endAlarm,
  deleteManager,
  runAlarmAll
} from '@/api/realTimeVideoSafetyManagement/safetyManager.js'

export default {
  mixins: [baseview, BaseDataGrid],
  name: 'SafetyDetectionCameraManage',
  components: {
  },
  computed: {
    dataGridMain() {
      return this.$refs[this.dxDataGridRef].instance
    },
  },
  data() {
    return {
      gridKey: 0,
      newId: 0,
      dxDataGridRef: 'cctvManageDataGridRef',
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd', //추가
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      cctvDataSource: [],
      cctvGrouprDataSource: [],
      grpNm:[]
    }
  },
  methods: {
    getManager() {
      getGroupList()
          .then(res => {
            this.cctvGrouprDataSource = res.list
            console.log(this.cctvGrouprDataSource)
          })
    },
    btnAdd() {
      let newRow = {
        gridKey: this.newId,
        monitoring_grp_id: '',
        token : '',
        chat_id : '',
        created_at : null,
        created_by : null,
        updated_at : null,
        updated_by : null,
        notification_on: false
      }
      this.newId++
      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
      this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.id, true)
    },
    btnSearch() {
      this.cctvDataSource = []
      getManagerList().then(managerRes => {
        console.log('managerRes', managerRes)
        if(managerRes.success) {
          this.cctvDataSource = []
          managerRes.list.forEach(element => {
            console.log('element', element)
            let new_row = element
            new_row['gridKey'] =`${element.monitoring_grp_id}_${element.chat_id}`
            this.cctvDataSource.push(new_row)
          });
          this.newId = managerRes.list.length

          console.log('this.cctvDataSource', this.cctvDataSource)


          console.log('this.newId', this.newId)
        }
      })
    },

    async btnSave() {
      let selectedMainRows = await this.dataGridMain.getSelectedRowsData();

      if (!selectedMainRows.length) {
        this.vToastify(this.$t('selectionData'), 'warn');
        return;
      }

      this.vToastifyPrompt(
          this.$t('doSaveData'),
          'info',
          async () => {
            this.dataGridMain.saveEditData();

            // ✅ Validate required fields
            if (selectedMainRows.some(el => !el.monitoring_grp_id.trim() || !el.chat_id.trim())) {
              this.vToastify(
                  `${this.$t('msgReqValidate')}, ${this.$t('grpID')}, ${this.$t('chatID')}, ${this.$t('token')}`,
                  'warn'
              );
              return;
            }

            // ✅ Convert notification_on to Boolean
            let payload = selectedMainRows.map(el => ({
              ...el,
              gridKey_temp: `${el.monitoring_grp_id}_${el.chat_id}`, // 새로운 key 값 설정
              notification_on: el.notification_on === true || el.notification_on === "true",
              userCd: getUserCd(),
              original_monitoring_grp_id: el.__created__ ? null : el.original_monitoring_grp_id,
              original_chat_id: el.__created__ ? null : el.original_chat_id
            }));

            console.log("🚀 Sending Data to API:", payload);
            payload.forEach(el0 => {
              this.cctvDataSource.forEach(el1=>{
                if(el0.gridKey === el1.gridKey) {
                  el1.gridKey = el0.gridKey_temp
                  return
                }
              })
            })
            console.log("🚀 cctvDataSource:", this.cctvDataSource);
            this.openLoading('saving');
            this.dataGridMain.beginUpdate();
            saveManager(payload, true)
                .then(res => {
                  this.btnSearch()
                })
                .catch(error => {
                  console.error('CCTV Save Error', error)
                })
                .finally(() => {
                  this.dataGridMain.clearSelection(); // ✅ 저장 후 선택 해제
                  this.dataGridMain.endUpdate()
                  this.endLoading()
                })
          //   try {
          //     let response = await saveManager(payload, true);
          //     console.log("✅ API Response:", response);
          //
          //     if (response.success) {
          //       // ✅ Refresh Grid Data
          //       this.btnSearch();
          //     } else {
          //       console.warn("⚠️ Save Failed:", response.message);
          //     }
          //   } catch (error) {
          //     console.error("❌ API Error:", error);
          //   } finally {
          //     this.dataGridMain.clearSelection();
          //     this.dataGridMain.endUpdate();
          //     this.endLoading();
          //   }
           },
          null,
          true
      );
    },

    async btnDelete() {
      try {
        let selectedMainRows = await this.dataGridMain.getSelectedRowsData();

        if (!selectedMainRows.length) {
          this.vToastify(this.$t('selectionData'), 'warn');
          return;
        }

        this.vToastifyPrompt(
            this.$t('doDeleteData'),
            'info',
            async () => {
              try {
                this.dataGridMain.beginUpdate();
                this.dataGridMain.saveEditData();
                this.openLoading('deleting');

                // Extract manager IDs for deletion
                const param = selectedMainRows
                    .filter(el => !el.__created__)
                    .map(el => ({
                      monitoring_grp_id: el.monitoring_grp_id,
                      chat_id: el.chat_id
                    }));

                // Get manager IDs of newly created rows
                const newlyCreatedIds = selectedMainRows
                    .filter(el => el.__created__)
                    .map(el => ({
                      monitoring_grp_id: el.monitoring_grp_id,
                      chat_id: el.chat_id
                    }));

                // Remove newly created items from cctvDataSource
                this.cctvDataSource = this.cctvDataSource.filter(
                    el => !newlyCreatedIds.some(
                        id => id.monitoring_grp_id === el.monitoring_grp_id && id.chat_id === el.chat_id
                    )
                );

                const finishEvent = () => {
                  this.dataGridMain.endUpdate();
                  this.FocusFirstRow(this.dataGridMain);
                  this.endLoading();
                };

                if (param.length !== 0) {
                  await deleteManager(param, true)
                      .then(() => {
                        this.btnSearch();
                      })
                      .catch(error => {
                        console.error('Error deleting manager:', error);
                        this.vToastify(this.$t('deleteError'), 'error');
                      })
                      .finally(() => {
                        finishEvent();
                      });
                } else {
                  finishEvent();
                }
              } catch (error) {
                console.error('Unexpected error:', error);
                this.vToastify(this.$t('deleteError'), 'error');
              }
            },
            null,
            true
        );
      } catch (error) {
        console.error('Error fetching selected rows:', error);
        this.vToastify(this.$t('fetchError'), 'error');
      }
    },

    onEditingStart(e) {
      if (!e.data.__created__) {
        if (!e.data.original_monitoring_grp_id) {
          e.data.original_monitoring_grp_id = e.data.monitoring_grp_id;
        }
        if (!e.data.original_chat_id) {
          e.data.original_chat_id = e.data.chat_id;
        }
      }
    },
    onFocusedRowChanged(e) {

    },
    onFullRun() {
      runAlarmAll()
          .then(res => {
            this.btnSearch()
          })
    },
    onRun(param, isRun) {
      console.log("🚀 onRun Triggered - param:", param, "isRun:", isRun);

      if (!param) {
        console.error("❌ Error: param is undefined");
        return;
      }

      if (isRun) {
        runAlarm(param)
            .then(res => {
              console.log("✅ runAlarm Response:", res);
              this.btnSearch();
            })
            .catch(error => console.error("❌ runAlarm Error:", error));
      } else {
        endAlarm(param)
            .then(res => {
              console.log("✅ endAlarm Response:", res);
              this.btnSearch();
            })
            .catch(error => console.error("❌ endAlarm Error:", error));
      }
    }

  },
  mounted() {
    this.getManager()
    this.btnSearch()
  },
}
</script>

<style lang="scss">
.cctv-api-server-manage {
  $appBarHeight: 65px;
  $cardTitleHeight: 62px;
  $conditionOneHeight: 46px;
  $paddingHeight: 8px;
  $spare: 3.5vh;
  > div {
    position: relative;
  }
  &-layout-col-height {
    // max-width: 100% !important;
    min-height: calc(100vh - (#{$appBarHeight} + #{$cardTitleHeight} + #{$conditionOneHeight} + (#{$paddingHeight} * 5.8) + #{$spare})) !important;
  }
}
</style>